Here’s a simplified production-style FastAPI login endpoint showing password verification and JWT creation.

```python
from fastapi import APIRouter, HTTPException
from pydantic import BaseModel
from jose import jwt
from passlib.context import CryptContext
from datetime import datetime, timedelta
from typing import Dict

router: APIRouter = APIRouter()

pwd_context: CryptContext = CryptContext(schemes=["bcrypt"], deprecated="auto")
SECRET_KEY: str = "secret"
ALGORITHM: str = "HS256"

class LoginRequest(BaseModel):
    username: str
    password: str

fake_user_db: Dict[str, str] = {
    "yash": pwd_context.hash("password123")
}


def verify_password(plain_password: str, hashed_password: str) -> bool:
    try:
        return pwd_context.verify(plain_password, hashed_password)
    except Exception:
        return False


def create_access_token(data: Dict[str, str]) -> str:
    try:
        to_encode: Dict[str, str] = data.copy()
        expire: datetime = datetime.utcnow() + timedelta(minutes=30)
        to_encode.update({"exp": expire})
        token: str = jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)
        return token
    except Exception as e:
        raise HTTPException(status_code=500, detail="Token creation failed")


@router.post("/login")
async def login(payload: LoginRequest) -> Dict[str, str]:
    try:
        hashed_password: str | None = fake_user_db.get(payload.username)

        if not hashed_password or not verify_password(payload.password, hashed_password):
            raise HTTPException(status_code=401, detail="Invalid credentials")

        token: str = create_access_token({"sub": payload.username})
        return {"access_token": token}

    except HTTPException:
        raise
    except Exception:
        raise HTTPException(status_code=500, detail="Login failed")
```

Notice the layered responsibility: validation → verification → token generation → controlled failure paths. Production APIs assume failure is normal, not exceptional.

Here’s a realistic pytest example testing a protected FastAPI endpoint using an auth token.

```python
from fastapi.testclient import TestClient
from typing import Dict
import pytest

client: TestClient = TestClient(app=None)


def get_auth_token() -> str:
    try:
        response = client.post(
            "/login",
            json={"username": "yash", "password": "password123"}
        )
        data: Dict[str, str] = response.json()
        return data["access_token"]
    except Exception:
        pytest.fail("Failed to obtain auth token")


def test_protected_tasks_endpoint() -> None:
    try:
        token: str = get_auth_token()

        response = client.get(
            "/tasks",
            headers={"Authorization": f"Bearer {token}"}
        )

        assert response.status_code == 200
        body: Dict = response.json()
        assert isinstance(body, dict) or isinstance(body, list)

    except AssertionError:
        raise
    except Exception as e:
        pytest.fail(f"Unexpected test failure: {e}")
```

Notice the structure: token acquisition isolated, authenticated request simulated, failures surfaced cleanly. Tests should fail loudly and explain why — ambiguity wastes debugging time.
